const today = new Date().toISOString().slice(0, 10);
const FEISHU_WEBHOOK = $env.N8N_01_FEISHU_WEBHOOK || 'https://open.feishu.cn/open-apis/bot/v2/hook/YOUR_N8N_01_FEISHU_WEBHOOK';
const BITABLE_APP = $env.N8N_01_FEISHU_BITABLE_TOKEN || 'YOUR_N8N_01_FEISHU_BITABLE_TOKEN';
const BITABLE_TABLE = $env.N8N_01_FEISHU_TABLE_CLASSIC || 'YOUR_N8N_01_FEISHU_TABLE_CLASSIC';
const startTime = Date.now();
return [{ json: { date: today, feishuWebhook: FEISHU_WEBHOOK, bitableApp: BITABLE_APP, bitableTable: BITABLE_TABLE, startTime } }];

const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || {};
const config = $('初始化配置').first().json;

if (status !== 200 || !body.items) {
    return [{ json: { items: [], trendingItems: [], error: `HTTP ${status}`, date: config.date, feishuWebhook: config.feishuWebhook, bitableApp: config.bitableApp, bitableTable: config.bitableTable } }];
}

const items = body.items.map(repo => ({
    name: repo.full_name,
    stars: repo.stargazers_count,
    description: (repo.description || '').substring(0, 200),
    url: repo.html_url,
    createdAt: repo.created_at,
    language: repo.language || 'N/A',
    topics: (repo.topics || []).join(', ')
}));

const uniqueMap = new Map();
items.forEach(item => { if (!uniqueMap.has(item.name)) uniqueMap.set(item.name, item); });
const uniqueItems = Array.from(uniqueMap.values());

const existingItems = uniqueItems.filter(i => i.stars >= 10000);
const trendingItems = uniqueItems.filter(i => i.stars < 10000 && i.stars >= 100);

return [{ json: { items: existingItems, trendingItems, totalFound: body.total_count, date: config.date, feishuWebhook: config.feishuWebhook, bitableApp: config.bitableApp, bitableTable: config.bitableTable } }];

const data = $input.first().json;
const items = data.items || [];
const topItems = items.slice(0, 20);
const descs = topItems.map(i => (i.description || '').substring(0, 150)).filter(d => d.length > 10 && /[a-zA-Z]/.test(d));

let translationOk = true;
let translationError = '';

if (descs.length === 0) {
    topItems.forEach(i => { i.descriptionCn = i.description || '' });
    return [{ json: { ...data, items, topItems, translationOk: true, translationError: '', translatedCount: 0 } }];
}

const batchSize = 10;
const translatedMap = {};

for (let i = 0; i < descs.length; i += batchSize) {
    const batch = descs.slice(i, i + batchSize);
    const prompt = '将以下' + batch.length + '个项目描述翻译成中文。规则：\n1. 通顺易懂，50字内\n2. 保留技术术语\n3. 每行一个翻译结果，不要编号\n\n待翻译：\n' + batch.map((d, idx) => (idx+1) + '. ' + d).join('\n') + '\n\n翻译结果：';
    try {
        const response = await this.helpers.httpRequest({
            method: 'POST', url: `http://${$env.N8N_01_OLLAMA_HOST || 'localhost'}:${$env.N8N_01_OLLAMA_PORT || '11434'}/v1/chat/completions`,
            headers: { 'Content-Type': 'application/json' },
            body: { model: 'qwen2.5:3b', messages: [{ role: 'system', content: '你是项目描述翻译助手。' }, { role: 'user', content: prompt }], temperature: 0.1, max_tokens: 1500, stream: false }, timeout: 120000
        });
        const content = response.choices?.[0]?.message?.content || '';
        const lines = content.split('\n').map(l => l.replace(/^\d+[\.\s]+/, '').trim()).filter(l => l.length > 0);
        const matchCount = Math.min(batch.length, lines.length);
        for (let j = 0; j < matchCount; j++) {
            if (lines[j]) translatedMap[batch[j]] = lines[j];
        }
    } catch (e) {
        translationOk = false;
        translationError = e.message;
    }
}

topItems.forEach(item => {
    const desc = item.description || '';
    item.descriptionCn = translatedMap[desc] || desc;
});

return [{ json: { ...data, items, topItems, translationOk, translationError, translatedCount: Object.keys(translatedMap).length, totalToTranslate: descs.length } }];

const data = $input.first().json;
const items = data.items || [];

const APP_ID = $env.N8N_01_FEISHU_APP_ID || 'YOUR_N8N_01_FEISHU_APP_ID';
const APP_SECRET = $env.N8N_01_FEISHU_APP_SECRET || 'YOUR_N8N_01_FEISHU_APP_SECRET';

let token = '';
try {
    const tokenResp = await this.helpers.httpRequest({
        method: 'POST', url: 'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal',
        headers: { 'Content-Type': 'application/json' },
        body: { app_id: APP_ID, app_secret: APP_SECRET }, timeout: 10000
    });
    token = tokenResp.tenant_access_token;
} catch (e) {
    return [{ json: { ...data, error: 'Token获取失败: ' + e.message, writeCount: 0, tokenOk: false } }];
}
if (!token) return [{ json: { ...data, error: 'Token为空', writeCount: 0, tokenOk: false } }];

const records = items.map(item => ({
    fields: {
        '项目名': item.name, 'Stars': item.stars, '描述': item.description,
        '中文描述': item.descriptionCn || '', '链接': { text: item.name, link: item.url },
        '语言': item.language, '拉取日期': new Date(data.date).getTime()
    }
}));

let writeResult = null;
try {
    writeResult = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://open.feishu.cn/open-apis/bitable/v1/apps/${data.bitableApp}/tables/${data.bitableTable}/records/batch_create`,
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: { records }, timeout: 60000
    });
} catch (e) {
    return [{ json: { ...data, error: '写入失败: ' + e.message, writeCount: 0, tokenOk: true } }];
}

const writeCount = writeResult?.data?.records?.length || 0;
return [{ json: { ...data, bitableResult: writeResult, writeCount, tokenOk: true } }];

const data = $input.first().json;
const config = $('初始化配置').first().json;
const items = data.items || [];
const date = config.date;
const feishuWebhook = config.feishuWebhook;

// 翻译状态
const transOk = data.translationOk !== false;
const transCount = data.translatedCount || 0;
const transTotal = data.totalToTranslate || 0;
const transErr = data.translationError || '';

// 写入状态
const writeOk = data.tokenOk !== false;
const writeCount = data.writeCount || 0;
const writeErr = data.error || '';

let md = '';

// 状态区
if (!writeOk) {
    md += '⚠️ **表格写入失败**: ' + writeErr + '\n\n';
}
if (!transOk && transTotal > 0) {
    md += '⚠️ **翻译服务异常**: ' + transErr.substring(0, 80) + '\n   已翻译 ' + transCount + '/' + transTotal + ' 条\n\n';
}

md += '**📊 数据概览**\n';
md += '· 收录项目: **' + items.length + '** 个\n';
md += '· 表格写入: ' + (writeOk ? '✅ ' + writeCount + ' 条' : '❌ 失败') + '\n';
md += '· 翻译状态: ' + (transOk ? '✅ ' + transCount + '/' + transTotal : '⚠️ 部分失败 ' + transCount + '/' + transTotal) + '\n\n';

// 项目列表
if (items.length > 0) {
    const tier1 = items.filter(i => i.stars >= 50000);
    const tier2 = items.filter(i => i.stars >= 20000 && i.stars < 50000);
    const tier3 = items.filter(i => i.stars >= 10000 && i.stars < 20000);

    if (tier1.length > 0) {
        md += '**👑 超级巨星** (' + tier1.length + '个)\n';
        tier1.slice(0, 6).forEach((item, i) => {
            const desc = (item.descriptionCn || item.description || '').substring(0, 50);
            md += (i+1) + '. [' + item.name + '](' + item.url + ') ⭐' + item.stars.toLocaleString() + '\n   ' + desc + '\n';
        });
        md += '\n';
    }
    if (tier2.length > 0) {
        md += '**🌟 顶级项目** (' + tier2.length + '个)\n';
        tier2.slice(0, 6).forEach((item, i) => {
            const desc = (item.descriptionCn || item.description || '').substring(0, 50);
            md += (i+1) + '. [' + item.name + '](' + item.url + ') ⭐' + item.stars.toLocaleString() + '\n   ' + desc + '\n';
        });
        md += '\n';
    }
    if (tier3.length > 0) {
        md += '**⭐ 热门项目** (' + tier3.length + '个)\n';
        tier3.slice(0, 5).forEach((item, i) => {
            const desc = (item.descriptionCn || item.description || '').substring(0, 50);
            md += (i+1) + '. [' + item.name + '](' + item.url + ') ⭐' + item.stars.toLocaleString() + '\n   ' + desc + '\n';
        });
        if (tier3.length > 5) md += '... 等' + tier3.length + '个\n';
    }
}

md += '\n---\n📅 ' + date + ' · 数据已同步至飞书表格';

const payload = {
    msg_type: 'interactive',
    card: {
        schema: '2.0',
        config: { wide_screen_mode: true },
        header: {
            title: { tag: 'plain_text', content: '📊 GitHub AI 热门项目 ' + date },
            template: 'blue'
        },
        body: { elements: [{ tag: 'markdown', content: md }] }
    }
};

try {
    await this.helpers.httpRequest({ method: 'POST', url: feishuWebhook, headers: { 'Content-Type': 'application/json' }, body: payload, timeout: 10000 });
    return [{ json: { message: '经典通知已发送', date, itemCount: items.length } }];
} catch (e) {
    return [{ json: { error: '通知发送失败: ' + e.message, date } }];
}

